import{_ as i,o as t,c as l,ag as n}from"./chunks/framework.DXGyWiRo.js";const r="/images/uebung050.jpg",s="/images/uebung051.jpg",u="/images/uebung052.jpg",o="/images/uebung053.jpg",p="/images/uebung054.jpg",k=JSON.parse('{"title":"Übung Lektion 32","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung32.md","filePath":"lektionen/uebung32.md"}'),a={name:"lektionen/uebung32.md"};function d(h,e,q,m,g,c){return t(),l("div",null,[...e[0]||(e[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-32" tabindex="-1">Übung Lektion 32 <a class="header-anchor" href="#ubung-lektion-32" aria-label="Permalink to &quot;Übung Lektion 32&quot;">​</a></h1><p>A) Bestimmen Sie folgende Verbformen und bilden Sie die in Person, Zahl und Genus verbis entsprechenden Imperfektformen:</p><ol><li>हरि्ष्यन्ते । अहरन्त</li><li>घातयति । अघातयत्</li><li>विहन्ति । व्यहन्</li><li>घ्नन्ति । अघ्नन्</li><li>विस्मर्यते । व्यस्मर्यत</li><li>प्रस्थास्यन्ते । प्रातिष्ठन्त</li><li>प्रस्तुते । प्रास्तुत</li><li>स्रक्ष्यन्ति । असृजन्</li><li>सेक्ष्यन्ति । असिञ्चन्</li><li>श्रूयते । अश्रूयत</li><li>शक्नोति । अशक्नोत्</li><li>वर्त्स्यन्ति । अवर्तन् (अवर्तन्त)</li><li>वसते । अवसत</li><li>वत्स्यन्ति । अवसन्</li><li>वदति । अवदत्</li><li>प्रवक्ति । प्रावक्</li><li>वेशयन्ते । अवेशयन्त</li><li>लुभ्यन्ति । अलुभ्यन्</li><li>उपलप्स्यन्ते । उपालभन्त</li><li>रुन्द्धे । अरुन्द्ध</li><li>रोदिति । अरोदित्</li><li>रक्षन्ति । अरक्षन्</li><li>युध्यन्ते । अयुध्यन्त</li><li>युञ्जते । अयुञ्जत</li><li>युजन्ति । अयजन्</li><li>म्रियते । अम्रियत</li><li>विमोचयन्ति । व्यमोचयन्</li><li>मंस्यन्ते । अमन्यन्त</li><li>मोहिष्यति । अमुह्यत्</li><li>भवति । अभवत्</li><li>भुनक्ति । अभुनक्</li><li>भिनत्ति । अभिनत्</li><li>भञ्जन्ति । अभञ्जन्</li><li>भजते । अभजत</li><li>ब्रूते । अब्रूत</li><li>विजेष्यन्ते । व्यजयन्त</li><li>जायन्ते । अजायन्त</li><li>छिन्त्ते । अछिन्त्त</li><li>आचरन्ति । आचरन्</li><li>चोर्यन्ते । अचोर्यन्त</li><li>आगमिष्यन्ति । आगच्छन्</li><li>कामयन्ते । अकामयन्त</li><li>खादन्ति । अखादन्</li><li>विक्रेष्यते । व्यक्रीणीत</li><li>संस्करोति । समकरोत्</li><li>क्रुध्यन्ति । अक्रुध्यन्</li><li>एषयन्ति । ऐष्यन्</li><li>संयन्ति । समायन्</li><li>समास्ते । समास्त</li><li>व्यङ्क्ते । व्याङ्क्त</li><li>सन्ति । आसन्</li><li>अस्यन्ति । आस्यन्</li><li>अश्नाति । आश्नात्</li><li>अश्नुते । आश्नुत</li><li>प्राप्स्यन्ति । प्राप्नुवन्</li><li>अदन्ति । आदन्</li><li>प्रभोत्स्यन्ते । प्राभुध्यन्त</li><li>बध्नाति । अबध्नात्</li><li>प्रक्ष्यन्ति । अपृच्छन्</li><li>पुनाति । अपुनात्</li><li>पान्ति । अपान्</li><li>पास्यन्ति । अपिबन् । अपान्</li><li>पद्यते । अपद्यत</li><li>पातयति । अपातयत्</li><li>पक्ष्यन्ति । अपचन्</li><li>नर्तिष्यति । अनृत्यत्</li><li>आनेष्यन्ति । आनयन्</li><li>द्वेष्टि । अद्वेट्</li><li>द्रक्ष्यन्ति । अपश्यन्</li><li>दूषयन्ति । अदूषयन्</li><li>उपदेक्ष्यन्ति । उपादिशन्</li><li>धक्ष्यति । अदहत्</li><li>तनोति । अतनोत्</li><li>प्रजानीते । प्राजानीत</li><li>जीवन्ति । अजीवन्</li></ol><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>आसीत्क्षत्रिय उपपन्नो गुणैरिष्टै रूपवान् । स जनेन्द्राग्रे ऽतिष्ठत् । स देवानयजतारीनजयज्जनानपान्महापुण्यमकरोत् । तस्मान्मृत्वा देवलोके पुनर्भवमलभत ॥१॥ जनस्येन्द्रस्याग्रे । महत्पुण्यम् । देवानां लोके । Es war einmal ein Fürst, der alle wünschenswerten Vorzüge hatte, von schöner Gestalt. Er stach unter allen Menschenfürsten hervor. Er opferte den Göttern, besiegte die Feinde, hütete das Volk und tat Verdienstvolles; deshalb wurde er nach seinem Tod in einer Götterwelt wiedergeboren.</p><p>ब्राह्मणो महानगरे ऽवसत् । स पुत्रमागमय्यावक् । ब्राह्मणपुत्रो वेदं गुरावधीयीतेति । तच्छ्रुत्वा स पुत्रो ऽध्ययनाय गुरुमैत् । गुरुगृहे प्रविश्य गुरुमुपातिष्ठद्गुरुश्च तं पुत्रम् ब्राह्मणमपृच्छत् । ततस्तेन पुत्रेणान्नमादयत् ॥२॥ ब्राह्मणस्य पुत्रः । गुरोर्गृहे । Ein Brahmane wohnte in einer Großstadt. Es ließ seinen Sohn kommen und sprach: &quot;Ein Brahmanensohn soll den Veda bei einem Meister studieren.&quot; Auf diese Worte hin ging der Sohn zu einem Meister, um zu studieren. Er trat ins Haus des Meisters und trat ehrfürchtig vor den Meister. Der Meister erkundigte sich nach dem Brahmanen. Dann gab er jenem Sohn Speise zu essen.</p><p>राम आचर्यमुपसंगम्य वचनमब्रवीत् ॥३॥ Rāma ging zum Lehrer uns sprach die Worte.</p><p>ब्राह्मणा वेदमध्यैयत चाध्यापयंश्च देवांश्चायजन्नयजन्त च क्षत्रियाः श्रुतिमध्यैयत जनानरक्षन्महीमभुञ्जन्देवानयजन्त वैश्या वेदमध्यैयत देवानयजन्ताक्रीणन्व्यक्रीणत च द्विजदासास्तु शूद्रा आसन् ॥४॥ द्विजानां दासाः । Brahmanen haben den Veda studiert und gelehrt, den Götter als Opferherren und in fremdem Auftrag geopfert. Kṣatriyas haben den Veda studiert, das Volk behütet, die Erde genossen und den Göttern als Opferherren geopfert. Vaiśyas haben den Veda studiert, den Göttern als Opferherren geopfert, gekauft und verkauft. Śūdras aber waren Leibeigene der Zweimalgeborenen.</p><p>बुद्धपुत्राः सत्यमजानन्दुःखमरुन्धन्मोक्षं प्राप्नुवन् । बुद्धपुत्र इति बुद्धमार्गभिक्षुरुच्यते ॥५॥ बुद्धस्य पुत्राः । Söhne Buddhas haben die Wahrheit erkennt, das Leiden zum Stillstand gebracht und die Erlösung erreicht.</p><p><img src="'+r+'" alt=""><br> Abb.: सम्पन्नरूपा<br> [Bildquelle: James Crowley. -- <a href="http://www.flickr.com/photos/james_crowley/2141684597/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/james_crowley/2141684597/</a>. -- Zugriff am 2009-01-05. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>Anmerkung: ursprünglich wurde dieser an der Universität Tübingen jeweils im Wintersemester gehalten. Bei Lektion 32 begannen die zweiwöchigen Weihnachtsferien.</p><p>!!!Lösungen ohne Anspruch auf Vollständigkeit!!!</p><p>A) Bestimmen und übersetzen Sie folgende Wörter:</p><ol><li><p>देवस्य Gen. sg. zu deva m. &quot;des Gottes&quot;</p></li><li><p>उषितायाः Abl.Gen.sg.f.PPP zu vas 1P &quot;(von) der bewohnten&quot;</p></li><li><p>लप्स्यन्ते 1.pl.Ā.Fut zu labh 1Ā &quot;sie werden erhalten&quot;</p></li><li><p>गुरौ Lok.sg. zu guru m. &quot;beim Lehrer&quot;</p></li><li><p>भाव्यते 3.sg.Ind.Präs.Kaus.Passiv zu bhū 1P &quot;er wird hervorgebracht&quot;</p></li><li><p>अग्नये Dat.sg. zu agni m. &quot;dem Feuer&quot;</p></li><li><p>मोक्तुम् Inf. zu muc 6U &quot;um zu befreien&quot;</p></li><li><p>वितत्य Absol. zu vi-tan 8U &quot;nachdem er aufgespannt hat&quot;</p></li><li><p>स्मृत्यै Dat.sg. zu smṛti f. &quot;für die Vergegenwärtigung&quot;</p></li><li><p>देवताः Nom.Akk.pl. zu devatā f. &quot;die Gottheiten&quot;</p></li><li><p>ब्रवीति 3.sg.P.Ind.Präs. zu brū 2U &quot;er spricht&quot;</p></li><li><p>प्रक्ष्यन्ति 3.pl.P.Fut. zu prach 6P &quot;sie werden fragen&quot;</p></li><li><p>पततः Abl.Gen.sg.m.n.;  Akk.pl.m.Part.Präs.P zu pat 1P &quot;des fallenden&quot; u.s.w.</p></li><li><p>पत्स्यन्ते 3.pl.Ā.Fut. zu pad 4Ā &quot;sie werden schreiten&quot;</p></li><li><p>आसते 3.pl.Ā.Ind.Präs. ; [Dat.sg.m.n.Part.Präs.P.] zu ās 2Ā &quot;sie sitzen&quot; ; [&quot;dem Sitzenden&quot;]</p></li><li><p>महान्ति Nom.Akk.pl.n. zu mahānt &quot;die großen&quot;</p></li><li><p>घ्नता Instr.sg.m.n.Part.Präs.P. zu han 2P &quot;durch den Tötenden&quot;</p></li><li><p>आययन्ति 3.pl.P.Ind.Präs.Kaus. zu i 2P &quot;sie schicken&quot;</p></li><li><p>एषिता Nom.sg.f.Kaus.PPP zu iṣ 6P &quot;die wünschen gemachte&quot;</p></li><li><p>आनाय्य Absol.Kaus. zu ā-nī 1U &quot;nachdem er herbeiführen ließ&quot;</p></li><li><p>अनृताय Dat.sg. zu anṛta n. &quot;für die Lüge&quot;</p></li><li><p>पूजया Instr. sg. zu pūjā f. &quot;durch die Verehrung&quot;</p></li><li><p>प्रश्नेभ्यः Dat.Abl.pl. zu praśna m. &quot;(von) den Fragen&quot;</p></li><li><p>धक्ष्यन्ति 3.pl.P.Fut. zu dah 1P &quot;sie werden verbrennen&quot;</p></li><li><p>मृगान् Akk.pl. zu mṛga m. &quot;die Wildtiere&quot;</p></li><li><p>बोधिम् Akk.sg. zu bodhi f. &quot;die Einsicht&quot;</p></li><li><p>गुणैः Instr.pl. zu guṇa m. &quot;durch Eigenschaften&quot;</p></li><li><p>सन्ति 3.pl.P.Ind.Präs. ; Nom.Akk.pl.n.Part.Präs.P. zu as 2P &quot;sie sind&quot; ; &quot;die seienden / wahren / guten&quot;</p></li><li><p>यन्ति 3.pl.P.Ind.Präs. ; Nom.Akk.pl.n.Präs.P zu i 2P &quot;sie gehen&quot; ; &quot;die gehenden&quot;</p></li><li><p>क्रियते 3.sg.Ind.Präs.Pass. zu kṛ 8U &quot;es wird getan&quot;</p></li><li><p>विगत्य Absol. zu vi-gam 1P &quot;nachdem es vergangen ist&quot;</p></li><li><p>चरित्वा Absol. zu car 1P &quot;nachdem er geweidet ... hat&quot;</p></li><li><p>पीते lok.sg.m.n.PPP zu pā 1P &quot;im getrunkenen&quot;</p></li><li><p>अन्नानि Nom.Akk.pl zu anna n. &quot;die Speisen&quot;</p></li><li><p>जलम् Nom.Akk.sg. zu jala n. &quot;das Wasser&quot;</p></li><li><p>वक्ति 3.sg.P.Ind.Präs. zu vac 2P &quot;er sagt&quot;</p></li><li><p>उक्तिः Nom.sg. zu ukti f. &quot;der Ausspruch&quot;</p></li><li><p>अर्धात् Abl.sg.m.n. zu ardha 3 &quot;vom halben&quot;</p></li><li><p>अर्थेन Instr.sg. zu artha m. &quot;durch den Zweck&quot;</p></li><li><p>स्तूयन्ते 3.pl.Ind.Präs.Pass. zu stu 2U &quot;sie werden gepriesen&quot;</p></li><li><p>श्रोष्यति 3.sg.P.Fut. zu śru 5P &quot;er wird hören&quot;</p></li><li><p>स्रष्टुम् Inf. zu sṛj 6P &quot;um loszulassen&quot;</p></li><li><p>पशुम् Akk.sg. zu paśu m. &quot;das domestizierte Tier&quot;</p></li><li><p>स्तुतीः Akk.pl. zu stuti f. &quot;die Lobpreisungen&quot;</p></li><li><p>अरयः Nom.pl. zu ari m. &quot;die Feinde&quot;</p></li><li><p>जात्या Instr.sg. zu jāti f. &quot;durch die Geburt / Kaste&quot;</p></li><li><p>जाताम् Akk.sg.f.PPP zu jan 4Ā &quot;die geborene&quot;</p></li><li><p>देक्ष्यति 3.sg.P.Fut. zu diś 6U &quot;er wird zeigen&quot;</p></li><li><p>दर्शितः Nom.sg.m.Kaus.PPP zu dṛś &quot;der gezeigte&quot;</p></li><li><p>दुष्टाः Nom.pl.m;Nom.Akk.plf.PPP zu duṣ 4P &quot;verdorbene&quot;</p></li><li><p>द्विजातीन् Akk.pl.m. zu dvijāti 3 &quot;die zweimalgeborenen&quot;</p></li><li><p>मृत्योः Abl.Gen.sg. zu mṛtyu mm. &quot;des Todes, vom Tod&quot;</p></li><li><p>दुग्धानाम् Gen.pl.m.n.f.PPP zu duh 2U &quot;der gemolkenen&quot;</p></li><li><p>दिष्टिभिः Inst.pl. zu diṣṭi f. &quot;durch Anweisungen&quot;</p></li><li><p>मात्रायाम् Lok.sg. zu mātrā f. &quot;im Maß&quot;</p></li><li><p>अत्ति 3.sg.P.Ind.Präs.zu ad 2P &quot;er isst&quot;</p></li><li><p>जायन्ते 3.pl.Ā.Ind.Präs. zu jan 4Ā &quot;sie werden geboren&quot;</p></li><li><p>जीयन्ते 3.pl.Ind.Präs.Pass. zu ji 1P &quot;sie werden besiegt&quot;</p></li><li><p>जयन्ति 3.pl.P.Ind.Präs. ; Nom.Akk.pl.n.Part.Präs.P. zu ji 1P &quot;sie siegen&quot; ; &quot;die siegenden&quot;</p></li><li><p>जनयन्ति 3.pl.P.Ind.Präs.Kaus. zu jan 4Ā &quot;sie zeugen, sie erzeugen&quot;</p></li><li><p>प्रभृतेः Abl.Gen.sg. zu prabhṛti f. &quot;von Beginn an, des Beginns&quot;</p></li><li><p>उपतिष्ठन्ति 3.pl.P.Ind.Präs. ; Nom.Akk.pl.n.Part.Präs.P. zu upa-sthā 1P &quot;sie treten respektvoll vor&quot; ; &quot;die respektvoll vor ... tretenden&quot;</p></li><li><p>स्थित्याम् Lok.sg. zu sthiti f. &quot;in der Festsetzung&quot;</p></li><li><p>भिक्षुषु Lok.pl. zu bhikṣu m. &quot;bei den Mönchen&quot;</p></li><li><p>पक्त्वा Absol. zu pac 1U &quot;nachdem er gekocht hat&quot;</p></li><li><p>योद्धुम् Inf. zu yudh 4Ā &quot;um zu kämpfen&quot;</p></li><li><p>मारयित्वा Absol.Kaus. zu mṛ 4Ā &quot;nachdem er getötet hat&quot;</p></li><li><p>धेन्वा Instr.sg. zu dhenu f. &quot;durch die Milchkuh&quot;</p></li><li><p>मंस्यन्ते 3.pl.Ā.Fut. zu man 4Ā &quot;sie werden denken&quot;</p></li><li><p>इज्यते 3.sg.Ind.Präs.Pass. zu yaj 1U &quot;es wird geopfert&quot;</p></li><li><p>प्रोद्य Absol. zu pra-vad 1P &quot;nachdem er verkündet hat&quot;</p></li><li><p>लम्भयति 3.sg.Ind.Präs.Kaus. zu labh 4Ā &quot;er bewirkt, dass er erhält&quot;</p></li><li><p>स्थापिताभिः Inst.pl.f.Kaus.PPP zu sthā 1P &quot;durch die gestellten&quot;</p></li><li><p>शक्तिभ्यः Dat.Abl.pl. zu śakti f. &quot;(von) den Kräften&quot;</p></li><li><p>अलम् Adverb &quot;genug</p></li><li><p>हेतून् Akk.pl. zu hetu m. &quot;die Gründe&quot;</p></li><li><p>प्रतिमासु Lok.pl. zu pratimā f. &quot;bei den Bildnissen&quot;</p></li><li><p>यस्याः Abl.Gen.sg.f. zu yad 3 &quot;von welcher&quot;</p></li><li><p>हि Konjunktion &quot;denn, weil&quot;</p></li><li><p>तस्मिन् Lok.sg.m.n. zu tad 3 &quot;in diesem&quot;</p></li><li><p>ह्रियन्ते 3.pl.Ind.Präs.Pass. zu hṛ 1U &quot;sie werden genommen&quot;</p></li><li><p>अधिकृतेषु Lok.pl.m.n.PPP zu adhi-kṛ 8U &quot;bei den vorangestellten&quot;</p></li><li><p>अध्यापयति 2.sg.P.Ind.Präs.Kaus. zu adhi-i 2Ā &quot;er unterrichtet&quot;</p></li><li><p>वाचयन्ति 3.pl.P.Ind.Präs.Kaus. zu vac 2P &quot;sie lesen laut&quot;</p></li></ol><p>B) Übung zum Sandhi: Setzen Sie in folgenden Sätzen die Wörter in den Klammern ein. Achten Sie dabei besonders auf den Sandhi:</p><p>१. रामो ग्रामात् ... (द्वितीया विभक्तिः) ... गच्छति । (नगर । आर्यग्राम । महानगर । शत्रुग्राम । जयनगर । लोकेश्वरनगर । कविगृह )</p><blockquote><p>... ग्रामान्नगरं ... । ... ग्रामादार्यग्रामं ... । ... ग्रामान्महानगरं ... । ... ग्रामाच्शत्र्र्ग्रामं ... । ... ग्रामाच्छत्रुग्रामं ... । ... ग्रामाज्जयनगरं ... । ... ग्रामाल्लोकेश्वरनगरं ... । ... ग्रामाट्कविगृहं ... ॥</p></blockquote><p>२. जयन् ... (प्रथमा विभक्तिः) ...अरीन्हन्ति । (इन्द्रशत्रु । शत्रु । जितशत्रुक्षत्रिय । लोकेश्वर । तद्गुणशूर । देवता)</p><blockquote><p>जयन्निन्द्रशत्रुररीन्हन्ति ।</p><p>जयञ्शत्रुररीन्हन्ति । जयञ्छत्रुररीन्हन्ति ।</p><p>जयञ्जितशत्रुक्षत्रियो ऽरीन्हन्ति ।</p><p>जयंल्लोकेश्वरो ऽरीन्हन्ति ।</p><p>जयंस्तद्गुणशूरो ऽरीन्हन्ति ।</p><p>जयन्ती देवतारीन्हन्ति ॥</p></blockquote><p>३. न हि पुण्यवन्तस्ते ... (प्रथमा विभक्तिः) ... । (अरि । आर्यशत्रु)</p><blockquote><p>... ते ऽरयः । ... त आर्यशत्रवः ।</p></blockquote><p>४. देवता ... (तृतीया विभक्तिः) ... आद्यते । (ऋषि (एकवचने बहुवचने च) । इन्द्रदेवी)</p><blockquote><p>देवतर्षिणाद्यते । देवतर्षिभिराद्यते । देवतेन्द्रदेव्याद्यते ॥</p></blockquote><p>५.ब्राह्मणस् ... (सप्तमी विभक्तिरेकवचने बहुवचने च) ... एति । (नगर)</p><blockquote><p>ब्राह्मणो नगर एति । ब्राह्मणो नगरयेति ।<br> ब्राह्मणो नगरेष्वेति ॥</p></blockquote><p>६. रामो गृहे ... । (आस् । इ । वस्)</p><blockquote><p>रामो  गृह आस्ते । रामो  गृहयास्ते ।</p><p>रामो गृह एति । गृहयेति ।</p><p>रामो गृहे वसति ॥</p></blockquote><p>७. शूरेण ... (प्रथमा विभक्तिः) ... जीयते । (अरि । इन्द्रशत्रु । उक्तानृतनर । एष नर)</p><blockquote><p>शूरेणरिर्जीयते । शूरेणेन्द्रशत्रुर्जीयते । शूरेणोकानृतनरो जीयते । शूरेणैष नरो जीयते ॥</p></blockquote><p>८. कविना... (प्रथमा विभक्तिः) ... स्तूयन्ते । (आर्यदेव । इन्द्रादिदेव)</p><blockquote><p>कविनार्यदेवाः स्तूयन्ते । कविनेन्द्रादिदेवाः स्तूयन्ते ॥</p></blockquote><p>९. रामस् ... (द्वितीया विभक्तिः) ... गच्छति । (कवि । गृह । आर्यग्राम । अरिनगर । सुखता । तन्नगर । शूद्रग्राम । चन्द्रकीर्ति । ट्युबिङ्गन्नगर)</p><blockquote><p>रामः कविं गच्छति । रामो गृहं गच्छति । राम आर्यग्रामं गच्छति । रामो ऽरिनगरं गच्छति । रामः सुखतां गच्छति । रामस्तन्नगरं गच्छति । रामः शूद्रग्रामं गच्छति । रामश्चन्द्रकीर्तिं गच्छति । राम्ष्ट्युबिङ्गनगरं गच्छति (in die Stadt Tübingen) ॥</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: किम्यं रथो बालान्सुखतां वहति ।<br> [Bildquelle: Peter Davis. -- <a href="http://www.flickr.com/photos/pediddle/327856625/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/pediddle/327856625/</a>. -- Zugriff am 2009-01-05. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>C) Übersetzen Sie ins Sanskrit:</p><p>1.) Nachdem der Sohn qeboren ist , schickt die Brahmanin einen Diener zum Brahmanen. Der Brahmane lässt diesen Diener ins Haus eintreten und fragt dann nach dem Sohn. Der Diener sagt, dass der Sohn wohlauf ist. Als er das qehört hat, wird der Brahmane glücklich.</p><p>पुत्रे जाते ब्राह्मणी दासं ब्राह्मणं गमयति । ब्राह्मणस्तं दासं गृहं प्रवेश्य पुत्रं पृच्छति । सुभगः पुत्र इति दासो वक्ति । तच्छ्रुत्वा ब्राह्मणो सुखतां गच्छति ॥१॥</p><p>2.) Der Heilige hat das (ihm) getane Böse ertragen.</p><p>साधुना कृतं पापं सोढम् ॥२॥</p><p>3.) Sittlichkeit ist des Mannes Zier.</p><p>शीलं नरस्य भूषणम् ॥३॥</p><p>4.) Die mächtigen Krieger sind ins Brahmanendorf gegangen.</p><p>बलवद्योधा ब्राह्मणग्रामं गताः ॥४॥</p><p>5.) Das Mädchen weint.</p><p>बाला रोदिति ॥५॥</p><p>6.) Es gibt keine Krankheit gleich wie die Wohllust, es qibt keinen Feind wie die Verwirrung, es gibt kein Feuer wie den Zorn, es gibt kein Glück wie die Erkenntnis.</p><blockquote><p>नास्ति कामसमो व्याधिर्नास्ति मोहसमो रिपुः ।<br> नास्ति क्रोधसमो वह्निर्नास्ति ज्ञानसमं सुखम् ॥६॥</p></blockquote><p>7.) Ein Mann, den die Göttin behütet, ist glücklich.</p><p>यं नरं देवी रक्षति स सुखवान् ॥७॥</p><p>8.) Mit welchem Wind auch immer eine Wolke Wasser (वारि n.) lässt, mit dem Wind bewegt ein Gelehrter seinen Schirm.</p><blockquote><p>येन येन च वातेन वारिदो वारिं मुञ्चति ।<br> तेन तेन च वातेन छत्रं वहति पण्डितः ॥८॥</p></blockquote><p>9.) Es qibt keine fruchtbringenden Tätigkeiten von Ständen, Lebensstadien usw.</p><p>नैव सन्ति वर्णाश्रमादीनां फलदायिकाः क्रियाः ॥९॥</p><ol start="10"><li>Der Kreislauf der Wiedergeburten hat keinen Anfang.</li></ol><p>अनादिकालिकः संसारः ॥१०॥</p><ol start="11"><li>Es ist Zeit, sich dem Essen zu widmen.</li></ol><p>कालो भोजनं सेवितुम् ॥११॥</p><ol start="12"><li>Willkommen der Königin.</li></ol><p>स्वागतं देव्यै ॥१२॥</p><ol start="13"><li>Um der Himmel Willen tun die Menschen Verdienstvolles.</li></ol><p>स्वर्गेभ्यो नराः पुण्यं कुर्वते ॥१३॥</p><ol start="14"><li>Ein Mann, der aus Überheblichkeit, Gier, Zorn, oder Furcht ein Gerichtsurteil fälschlich spricht, qeht in eine Hölle.</li></ol><blockquote><p>मानाद्वा यदि वा लोभात्क्रोधाद्वा यदि वा भयाट् ।<br> यो न्यायमन्यथा ब्रूते स याति नरकं नरः ॥१४॥</p></blockquote><ol start="15"><li>Rāma ging auf Anweisung der Lehrers aus dem Dorf in die Stadt, betrat das Haus des heiligen Mannes, trat ehrerbietig vor den Heiligen und spricht: &quot;Lass ab vom Zorn!&quot;</li></ol><p>गुर्वादेशाद्रामो ग्रामान्नगरं गत्वा साधुगृहं प्रविश्य साधुमुपस्थायालं क्रोधेनेति वक्ति ॥१५।\\</p><ol start="16"><li>Immer (sei seine) Verbindung mit solchen, die in den Wissenschaften gewachsen sind, auf dass seine Erziehunq/qutes Verhalten wachse. (Dies) weil die Erziehunq/gutes Verhalten als Wurzel dieses (die Verbindung mit solchen) hat.</li></ol><p>नित्यो विद्यावृद्धसंयोगो विनयवृद्ध्यर्थम् । तन्मूलत्वाद्विनयस्य ॥१६॥</p><ol start="17"><li>Während der Lehrer steht, darf der Knabe nicht sitzen.</li></ol><p>गुरौ तिष्ठति बाल आसितुम् नार्हति ॥१७॥</p><ol start="18"><li>Es gibt keine bessere Zuflucht als Rāma.</li></ol><p>रामान्नास्ति परायणं प्रतरम् ॥१८॥</p><ol start="19"><li>Viṣṇumitra lässt den Rāma den Govinda ins Dorf schicken.</li></ol><p>विष्णुमित्रो रामेण गोविन्दं ग्रामं गमयति ॥१९॥</p><ol start="20"><li>Er lässt den Devadatta Reis kochen.</li></ol><p>स देवदत्तेनौदनं पाचयति ॥२०॥</p><ol start="21"><li>Dharma der Arier ist, dass junge Brahmanen die Abschnitte des Veda und der Smṛti immer wieder studieren.</li></ol><p>ब्राह्मणपुत्रा वेदाध्यायांश्च स्मृत्यध्यायांश्च पुनः पुनरधीयीरन्नित्यार्यधर्मः ॥२१॥</p><ol start="22"><li>Der Lehrer lehrte die Knaben den Veda und ging dann ins Haus.</li></ol><p>गुरुर्बालान्वेदमधाप्य गृहं गतः ॥२२॥</p><ol start="23"><li>Welches Amulett hat das Mädchen beschützt?</li></ol><p>कया रक्षिकया बाला रक्षिता ॥२३॥</p><ol start="24"><li>Wahrheit ist die Leuchte der Welt.</li></ol><p>सत्यं लोकस्य दीपः ॥२४॥</p><ol start="25"><li>Wem gehören diese Häuser?</li></ol><p>केषामिमानि गृहाणि ॥२५॥</p><ol start="26"><li>Dharma aller ist: Nichtverletzen, Wahrheit, Reinheit, Neidlosiqkeit, Nicht-Boshaftigkeit und Geduld.</li></ol><p>सर्वेषां धर्मो ऽहिंसा सत्यं शौचमनसूयानृशंस्यं क्षमा च ॥२६॥</p><ol start="27"><li>Die Kṣatriyas, die die Feinde besiegt haben, sitzen im Haus.</li></ol><p>जितशत्रुक्षत्रिया गृह आसते ॥२७॥</p><ol start="28"><li>Die ist eine (wirkliche) Gattin, die Liebes spricht; der aber ist ein (echter) Sohn, der lebt. Der lebt, der gute Eigenschaften besitzt; der lebt, der Dharma besitzt.</li></ol><blockquote><p>सा भार्या या प्रियं ब्रूते<br> स पुत्रो यस्तु जीवति ।<br> स जीवति गुणो यस्य<br> धर्मो यस्य स जीवति ॥२८॥</p></blockquote><ol start="29"><li>Der Götterfürst besiegt die Nichtarier, die Feinde des Indra sind. (Passiv)</li></ol><p>इन्द्रशत्र्वनार्या देवेन्द्रेण जीयन्ते ॥२९॥</p><ol start="30"><li>Yoga der Tat sind Askese (tapas n.), (Veda)rezitation, Dienstfertigkeit qegenüber dem HERRN. Er dient der Entfaltung der meditativen Versenkung und der Schwächung der kleśas.</li></ol><p>तपःस्वाध्यायेश्वरप्रणिधानानि क्रियायोगः । समाधिभावनार्थः क्लेशतनूकरनार्थश्च ॥३०॥</p><ol start="31"><li>Nahrungsaufnahme, Schlaf, Furcht und Paarung: dies ist eine Gemeinsamkeit der Menschen mit den Tieren. Im Dharma (liegt) nämlich deren hinzukommende Besonderheit. Vom Dharma verlassen sind sie den Tieren (Instr.) gleich.</li></ol><blockquote><p>आहारनिद्राभयमैथुनं च सामान्यमेतत्पशुभिर्नराणाम् ।<br> धर्मो हि तेषामधिको विशेषो धमेण हीनाः पशुभिः समानाः ॥३१॥</p></blockquote><ol start="32"><li>Die Leute werden geboren, um zu sterben.</li></ol><p>मरणाय जना जायन्ते ॥३२॥</p><ol start="33"><li>Höllen sind wegen des Bösen. Das Böse hat als Ursprung Armut. Armut entsteht durch Nicht-Geben.</li></ol><blockquote><p>भवन्ति नरकाः पापात्पापं दारिद्र्यसंभवम् ।<br> दारिद्र्यमप्रदानेन ॥३३॥</p></blockquote><ol start="34"><li>Es ist Dharma der Kṣatriyas, dass die Kṣatriyas die Leute vor den Feinden schützen.</li></ol><p>क्षत्रिया जनाञ्छत्रुभ्यो रक्षितुमर्हन्तीति क्षत्रियधर्मः ॥३४॥</p><ol start="35"><li>Deshalb haben die drei (tisras) Wissenschaften das Regiment als Wurzel. Das Reqiment , das Erziehunq/qutes Verhalten als Wurzel hat, bringt den Lebewesen (प्राणभृत्) Gewinn und sicheren Besitz.</li></ol><p>तस्मद्दण्डमूलास्तिस्रो विद्याः । विनयमूलो दण्डः प्राणभृतां योगक्षेमावहः ॥३५॥</p><ol start="36"><li>Böse Leute hören nicht (zu), wenn der Lehrer über den Dharma spricht.</li></ol><p>धर्मं वदति गुरौ दुर्जना न शृण्वन्ति ॥३६॥</p><ol start="37"><li>Diesem Rāma sei Verehrunq!</li></ol><p>रामाय तस्मै नमः ॥३७॥</p><ol start="38"><li>Der hehre Hari ist mein Weq/Ziel, der (seine) Feinde in einen Himmel schickte, die Seinen den Sinn des Veda wissen ließ, den Göttern Unsterblichkeitsspeise zu essen qab, den Schöpfer (विधि) den Veda lehrte, die Erde im Wasser (fest )setzte.</li></ol><blockquote><p>शत्रूनगमयत्स्वर्गं वेदार्थं स्वानवेदयत् ।<br> आशयच्चामृतं देवान्वेदमध्यापयद्विधिम् ।<br> आसयत्सलिले पृथ्वीं यः स मे श्रीहरिर्गतिः ॥३८॥</p></blockquote><ol start="39"><li>Viṣṇu zeiqt sich seinen Gläubiqen.</li></ol><p>विष्णुर्भक्तान्दर्शयते ॥३९॥</p><ol start="40"><li>Ein Reqiment, das nicht ausgeübt wird, bewirkt die Norm der Fische.</li></ol><p>अप्रणीतो दण्डो मात्स्यन्यायमुद्भावयति ॥४०।</p><ol start="41"><li>Wer Reichtümer besitzt, der hat Freunde: wer Reichtümer besitzt, der hat Verwandte; wer Reichtümer besitzt, der ist ein Mann (पुमान् Nom.sq.) in der Welt; wer Reichtümer besitzt, der ist nämlich ein Gelehrter.</li></ol><blockquote><p>यस्यार्थास्तस्य मित्राणि यस्यार्थास्तस्य बान्धवाः ।<br> यस्यार्थाः स पुमांल्लोके यस्यार्थाः स हि पण्डितः ॥४१॥</p></blockquote><ol start="42"><li>Das Feuer, das den Verstorbenen verbrennt, verbrennt auch die qute Witwe.</li></ol><p>मृतम् दहन्नग्निः सतीमपि दहति ॥४२॥</p><ol start="43"><li>Die Dienerin des Brahmanen hat die Speise qekocht und isst sie (nun).</li></ol><p>अन्नं पक्त्वा ब्राह्मणदास्यत्ति ॥४३॥</p><ol start="44"><li>Jetzt reicht&#39;s !</li></ol><p>अलं क्षमया ॥४४॥</p><ol start="45"><li>Diese Frucht reicht ihm zum Essen.</li></ol><p>इदं फलमलं तस्य खादनाय ॥४५॥</p><ol start="46"><li>Der innerste Tempelschrein ist ein Haus für das Bildnis des Gottes.</li></ol><p>देवप्रतिमायै गृहं गर्भगृहम् ॥४६॥</p><ol start="47"><li>Ein Dieb wird vom Diebstahl befreit durch Strafe oder durch Freilassung, Wenn aber der König (राजा Nom.sg.) den (Dieb) nicht bestraft, erhält er die Schuld des Diebes.</li></ol><blockquote><p>शासनाद्वा विमोक्षाद्वा स्तेनः स्तेयाfविमुच्यते ।<br> अशासित्वा तु तं राजा स्तेनस्याप्नोति किल्बिषम् ॥४७॥</p></blockquote><ol start="48"><li>Weil er einen Fehler beim Opfer gemacht hat, ist der Brahmane nicht würdig, Reichtümer zu empfangen.</li></ol><p>कृतयज्ञदोषत्वाद्ब्राह्मणो धनं लब्धुं नार्हति ॥४८॥</p><ol start="49"><li>Wenn die Initiationszeremonie stattqefunden hat, soll er sich den Veda und die Philosophie von Gelehrten, die Ökonomie von Departementsvorstehern aneignen (उपयुज्).</li></ol><p>वृत्तोपनयनस्त्रयीमान्वीक्षिकीं च शिष्टेभ्यो वार्त्तामध्यक्षेभ्य् उपयुञ्जीत ॥४९॥</p><ol start="50"><li>Vaiśyadharma ist, dass die Vaiśyas von Kauf und Verkauf leben. Da es so ist, kaufen und verkaufen die Vaiśyasöhne.</li></ol><p>क्रयेण च विक्रयेण च वैश्या जीवेयुरिति वैश्यधर्मः । एवं सति वैश्यपुत्राः क्रीणन्ति विक्रीणते च ॥५०॥</p><ol start="51"><li>Man soll die Wahrheit saqen, man soll Anqenehmes sagen; man soll nicht eine unanqenehrne Wahrheit saqen und man soll auch keine unangenehme Unwahrheit saqen. Dies ist der ewige Dharma.</li></ol><blockquote><p>सत्यं ब्रूयात्प्रियं ब्रूयान्न ब्रूयात्सत्यमप्रियम् ।<br> प्रियं च नानृतं ब्रूयादेष धर्मः सनातनः ॥५१॥</p></blockquote><ol start="52"><li>Auf Wiedersehen!</li></ol><p>पुनर्दर्शनाय ॥५२॥</p><p><img src="'+u+'" alt=""><br> Abb.: पुनर्दर्शनाय<br> Gateway of India = भारताचे प्रवेशद्वार, मुंबई<br> [Bildquelle: Rhaessner / Wikipedia. GNU FDLicense]</p><p>Übersetzen und bestimmen Sie folgende Wortformen:</p><ol><li><p>अदुग्ध 3.sg.Impf.Ā zu duh 2U &quot;er molk für sich&quot;</p></li><li><p>स्युः 3.Pl.Opt.P. zu as 2P &quot;sie seien&quot;</p></li><li><p>शूद्रायै Dat.sg. zu śūdrā f. &quot;für die Śūdrafrau&quot;</p></li><li><p>धेन्वाम् Lok.sg zu dhenu f. &quot;bei der Milchkuh&quot;</p></li><li><p>दास्याः Abl.Gen.sg. zu dāsī f. &quot;(von) der Dienerin&quot;</p></li><li><p>आस्त 3.sg.Impf.Ā zu ās 2Ā &quot;er saß&quot;</p></li><li><p>आनक् 3.sg.Impf.P zu añj 7P &quot;er salbte&quot;</p></li><li><p>साध्वीः Akk.pl. zu sādhvī &quot;die heiligen Frauen&quot;</p></li><li><p>प्राजानत 3.pl.Impf.Ā zu pra-jñā 9U &quot;sie erkannten für sich&quot;</p></li><li><p>अद्युः 3.pl.Opt.P zu ad 2P &quot;sie sollten essen&quot;</p></li><li><p>आसीत् 3.sg.Impf.P zu as 2P &quot;er war&quot;</p></li><li><p>हरौ Lok.sg.m. zu hari 3 &quot;im gelben&quot; bzw. hari m. &quot;in Hari&quot;</p></li><li><p>यस्याः Abl.Gen.sg.f. zu yad &quot;(von) welcher&quot;</p></li><li><p>सता Instr.sg.Part.Präs.P.m.n. zu as 2P &quot;durch den seienden / wahren / guten&quot;</p></li><li><p>तासु Lok.pl.f. zu tad 3 &quot;in diesen&quot;</p></li><li><p>तन्वीत 3.pl.Opt.Ā zu tan 8U &quot;er könnte aufspannen&quot;</p></li><li><p>अकुरुत 3.sg.Imp.Ā zu kṛ 5U &quot;er tat für sich&quot;</p></li><li><p>आगमय्य Absol.Kaus. zu ā-gam &quot;nachdem er kommen ließ&quot;</p></li><li><p>ताः Nom.Akk.pl.f. zu tad 3 &quot;diese&quot;</p></li><li><p>क्रेष्यन्ति 3.pl.Fut.P zu krī 9U &quot;sie werden kaufen&quot;</p></li><li><p>वसन्तानाम् Gen.pl. zu vasanta m. &quot;der Frühlinge&quot;</p></li><li><p>अतन्वत 3.pl.Impf.Ā zu tan 8U &quot;sie spannten für sich auf&quot;</p></li><li><p>अध्यैयत 3.pl.Impf.Ā zu adhi-i 2Ā &quot;sie studierten&quot;</p></li><li><p>गुर्व्यै Dat.sg.f. zu guru 3 (für die gewichtige, für die Meisterin&quot;</p></li><li><p>हराय Dat.sg. zu hara m.n. &quot;dem Hara (Śiva)&quot;</p></li><li><p>हारयत् Nom.Akk.sg.n.Part.Präs.Kaus.P zu hṛ 1U &quot;nehmen lassend&quot;</p></li><li><p>आहारयत् 3.sg.Impf.Kaus.P zu ā-hṛ &quot;er ließ bringen&quot; ; Nom.Akk.sg.n.Part.Präs.Kaus.P zu ā-hṛ 1U &quot;bringen lassend&quot;</p></li><li><p>हेतुभिः Instr.pl zu hetu m. &quot;durch die Gründe&quot;</p></li><li><p>धर्मवतः Abl.Gen.sg.m.n.Akk.pl.m. zu dharmavant &quot;gerecht&quot;</p></li><li><p>एनया Instr.sg.f. zu enad &quot;durch sie&quot;</p></li><li><p>तस्याम् Lok.sg.f. zu tad 3 &quot;in ihr&quot;</p></li><li><p>वेक्ष्यति 3,sg.Fut.P zu viś 6P &quot;er wird eintreten&quot;</p></li><li><p>अद्विषुः 3.pl.Impf.P zu dviṣ 2U &quot;sie hassten&quot; &lt;daneben: अद्विषन्&gt;</p></li><li><p>शक्तयः Nom.pl. zu śakti f. &quot;die Kräfte&quot;</p></li><li><p>आगमेभ्यः Dat.Abl.pl zu āgama m. &quot;(von) den Überlieferungen&quot;</p></li><li><p>व्यघ्नन् 3.pl.Impf.P zu vi-han 2P &quot;sie zerschlugen&quot;</p></li><li><p>भिन्दीरन् 3.pl.Opt.Ā zu bhid 7U &quot;sie spalteten für sich&quot;</p></li><li><p>भगवते Dat.sg.m.n. zu bhagavant &quot;dem ehrwürdigen&quot;</p></li><li><p>यत्सु Lok.plur.Part.Präs.m.n. zu i 2P &quot;während sie gehen&quot;</p></li><li><p>रोत्स्यन्ती Nom.sg.Part.Fut.f. zu rudh 7U &quot;die stoppen werdenden&quot;</p></li></ol><p><img src="'+o+'" alt=""><br> Abb.: श्रीगङ्गाधराय नमः<br> um 1740<br> [Bildquelle: Wikipedia. Public domain]</p><p>एकदा कश्चिद्वृद्धो ग्रामान्तरं गच्छन्पथि श्रान्तो ऽभवत् । अतः स विश्रमाय पार्श्वस्थितस्य चूततरोर्मूलमगच्छत् ॥ तस्मिन्वृक्षे पचेलिमानि फलान्यवर्तन्त । वृद्धस्य तेषु स्पृहा जाता । परं स वृक्षमारुह्य तानि ग्रहीतुं नाशक्नोत् ॥ दिष्ट्या तस्मिन् तरौ केचिद्वानराः फलानि खादन्तः स्थिताः । तानवलोक्य वृद्धः प्रहर्षं गतः । स किमकरोत् । स कतिचिदुपलानादाय वानरांल्लक्ष्यीकृत्य प्राक्षिपत् । वानराः कुपिताः कानिचित्फलान्यवचित्य वृद्धं प्रति प्राक्षिपन् । वृद्धः सहर्षं तान्यादाय स्वाभीष्टदेशं गतः ॥ अहो वृद्धस्य कौशलम् ॥ (aus: संस्कृतबालादर्श)</p><p>Eins ging ein Greis in ein anderes Dorf und war unterwegs müde. Um sich auszuruhen ging er an den Fuß eines Mangobaums, der auf der Seite stand. Auf diesem Baum waren reife Früchte. Der Greis bekam Lust auf sie. Aber er konnte nicht auf den Baum steigen und sie pflücken. Zum Glück waren auf dem Baum einige Affen, die Früchte fraßen. Als der Greis diese sah, freute er sich. Was tat er? Er nahm einige Steine zielte auf die Affen und warf sie. Die Affen waren wütend und pflückten einige Früchte und warfen sie auf den Greis. Greis nahm freudig die Früchte und ging dorthin, wo er wollte. Großartig! die List des Greises!</p><p>Erklärungen:</p><p>पथि Lok. sg. zu पथ् m. &quot;Weg&quot; (unregelmäßige Deklination)</p><p>लक्ष्यीकृ च्विऽ-षुffइx अन् लक्स्य + कृ : etwas zum लक्ष्य machen, was vorher nicht लक्ष्य war</p><p>आदाय Absolutiv zu आ-दा (3. Präsensklasse) &quot;nehmen&quot;</p><p><img src="'+p+'" alt=""><br> Abb.: वानरः कुपितः<br> Ranakpur<br> [Bildquelle: SkilliShots. -- <a href="http://www.flickr.com/photos/skillicorn/3028654887/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/skillicorn/3028654887/</a>. -- Zugriff am 2009-01-05. -- <a href="http://creativecommons.org/licenses/by-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine Bearbeitung)]</p>',151)])])}const z=i(a,[["render",d]]);export{k as __pageData,z as default};
